mapper.select:
SELECT DISTINCT m.id::text AS id, m.group_id::text AS "groupId", m.parent_id::text AS "parentId", m.menu_code AS "menuCode", m.menu_name AS "menuName", m.path, m.icon, m.roles, m.target, m.active_yn AS "activeYn", m.sort_order AS "sortOrder", m.created_at AS "createdAt", m.updated_at AS "updatedAt" FROM menu m JOIN menu_group mg ON mg.id = m.group_id JOIN permission_menu pm ON pm.menu_id = m.id JOIN user_permission up ON up.permission_id = pm.permission_id WHERE m.active_yn = 'Y' AND mg.use_yn = 'Y' AND up.user_id = ${userId}
AND mg.group_code = #{groupCode}
ORDER BY mg.sort_order, m.sort_order

SELECT m.id::text AS id, m.group_id::text AS "groupId", m.parent_id::text AS "parentId", m.menu_code AS "menuCode", m.menu_name AS "menuName", m.path, m.icon, m.roles, m.target, m.active_yn AS "activeYn", m.sort_order AS "sortOrder", m.created_at AS "createdAt", m.updated_at AS "updatedAt" FROM menu m JOIN menu_group mg ON mg.id = m.group_id WHERE m.active_yn = 'Y' AND mg.use_yn = 'Y' AND array_length(m.roles, 1) IS NULL
AND mg.group_code = #{groupCode}
ORDER BY mg.sort_order, m.sort_order

SELECT mg.id::text AS id, mg.group_code AS "groupCode", mg.group_name AS "groupName", mg.description, mg.use_yn AS "useYn", mg.sort_order AS "sortOrder", mg.created_at AS "createdAt", mg.updated_at AS "updatedAt" FROM menu_group mg
AND mg.use_yn = #{useYn}
ORDER BY mg.sort_order
